 25→function formatTokens(tokens: number) {
 26→	if (tokens >= 1_000_000) return `${(tokens / 1_000_000).toFixed(1)}M`;
 27→	if (tokens >= 1_000) return `${(tokens / 1_000).toFixed(1)}K`;
 28→	return tokens.toString();
 29→}
