 66→			</span>
 67→		),
 68→	},
 69→	{
 70→		accessorKey: "success_rate",
 71→		header: () => (
 72→			<span className="flex items-center">
 73→				Success Rate
 74→				<InfoTooltip text="Average session quality score (0–100): rewards git commits, high output ratio, and skill usage; deducts for errors and abandoned sessions." />
 75→			</span>
 76→		),
 77→		cell: ({ row }) => {
 78→			const rate = row.original.success_rate || 0;
 79→			const color =
 80→				rate >= 70
 81→					? "text-status-success-icon"
 82→					: rate >= 50
 83→						? "text-status-warning-icon"
 84→						: "text-status-error-icon";
 85→			return (
 86→				<span className={`font-semibold ${color}`}>{rate.toFixed(0)}%</span>
 87→			);
 88→		},
 89→	},
 90→	{
 91→		accessorKey: "cost",
