 98→		accessorKey: "success_rate_trend",
 99→		header: "Trend",
100→		cell: ({ row }) => {
101→			const trend = row.original.success_rate_trend || 0;
102→			const icon = trend > 0 ? "\u2191" : trend < 0 ? "\u2193" : "-";
103→			const color =
104→				trend > 0
105→					? "text-status-success-icon"
106→					: trend < 0
107→						? "text-status-error-icon"
108→						: "text-muted";
109→			return (
110→				<span className={`font-semibold ${color}`}>
111→					{icon} {Math.abs(trend).toFixed(1)}%
112→				</span>
113→			);
114→		},
115→	},
