312→						<Select
313→							value={selectedMetric}
314→							onValueChange={(v) =>
315→								setSelectedMetric(v as DimensionAnalysisInput["metric"])
316→							}
317→						>
318→							<SelectTrigger className="w-full">
319→								<SelectValue />
320→							</SelectTrigger>
321→							<SelectContent>
322→								<SelectItem value="session_count">Session Count</SelectItem>
323→								<SelectItem value="avg_duration">Avg Duration (min)</SelectItem>
324→								<SelectItem value="total_duration">
325→									Total Duration (hours)
326→								</SelectItem>
