347→							}
348→						>
349→							<SelectTrigger className="w-full">
350→								<SelectValue />
351→							</SelectTrigger>
352→							<SelectContent>
353→								<SelectItem value="session_archetype">Session Type</SelectItem>
354→								<SelectItem value="model_used">Model Used</SelectItem>
355→								<SelectItem value="user_id">User/Developer</SelectItem>
356→								<SelectItem value="project_path">Project</SelectItem>
357→								<SelectItem value="repository">Repository</SelectItem>
