371→							onValueChange={(v) => {
372→								const value = v === "none" ? "" : v;
373→								setSelectedSplitBy(
374→									value as DimensionAnalysisInput["dimension"] | "",
375→								);
376→								if (!value) setShowPercentage(false);
377→							}}
378→						>
379→							<SelectTrigger className="w-full">
380→								<SelectValue />
381→							</SelectTrigger>
382→							<SelectContent>
383→								<SelectItem value="none">None</SelectItem>
384→								<SelectItem value="session_archetype">Session Type</SelectItem>
385→								<SelectItem value="model_used">Model Used</SelectItem>
386→								<SelectItem value="user_id">User/Developer</SelectItem>
387→								<SelectItem value="repository">Repository</SelectItem>
388→							</SelectContent>
389→						</Select>
390→					</div>
391→				</div>
392→
393→				{selectedSplitBy && (
394→					<div className="mb-4 flex justify-end items-center gap-3">
395→						<span className="text-sm text-muted">Scale to 100%</span>
396→						<Switch
397→							checked={showPercentage}
398→							onCheckedChange={setShowPercentage}
399→						/>
400→					</div>
401→				)}
402→
403→				{dimensionLoading ? (
404→					<div className="flex items-center justify-center h-64">
405→						<div className="text-center">
406→							<Spinner className="mb-2" />
407→							<p className="text-muted">Loading chart...</p>
408→						</div>
409→					</div>
410→				) : (
411→					<DimensionAnalysisChart
412→						data={dimensionData || []}
413→						dimension={selectedDimension}
414→						metric={selectedMetric}
415→						split_by={selectedSplitBy || undefined}
416→						showPercentage={showPercentage}
417→						userMap={userMap}
418→					/>
419→				)}
420→			</AnalyticsCard>
421→
422→			{/* Sessions Table */}
423→			<AnalyticsCard>
424→				<div className="flex items-center justify-between mb-4">
425→					<div>
426→						<h3 className="text-lg font-semibold">
427→							Recent Sessions ({filteredSessions.length})
428→						</h3>
429→					</div>
430→					<div className="flex gap-3">
431→						<MultiSelect
432→							options={repositories}
433→							selected={selectedRepositories}
434→							onChange={setSelectedRepositories}
435→							placeholder="All Repositories"
436→							className="w-48"
437→						/>
