import type {
	DimensionAnalysisInput,
	SessionAnalytics,
} from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, Clock, Timer } from "lucide-react";
import { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { MultiSelect } from "@/components/analytics/MultiSelect";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { DimensionAnalysisChart } from "@/components/charts/DimensionAnalysisChart";
import { DataTable } from "@/components/ui/data-table";
import { InfoTooltip } from "@/components/ui/InfoTooltip";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { Spinner } from "@/components/ui/spinner";
import { Switch } from "@/components/ui/switch";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useUserMap } from "@/hooks/useUserMap";
import { calculateCost, formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

export function SessionsListPage() {
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [selectedRepositories, setSelectedRepositories] = useState<string[]>(
		[],
	);
	const [selectedUsers, setSelectedUsers] = useState<string[]>([]);

	const [selectedDimension, setSelectedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("project_path");
	const [selectedMetric, setSelectedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [selectedSplitBy, setSelectedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");
	const [showPercentage, setShowPercentage] = useState(false);

	const [debouncedDimension, setDebouncedDimension] =
		useState<DimensionAnalysisInput["dimension"]>("project_path");
	const [debouncedMetric, setDebouncedMetric] =
		useState<DimensionAnalysisInput["metric"]>("session_count");
	const [debouncedSplitBy, setDebouncedSplitBy] = useState<
		DimensionAnalysisInput["dimension"] | ""
	>("");

	useEffect(() => {
		const timer = setTimeout(() => {
			setDebouncedDimension(selectedDimension);
			setDebouncedMetric(selectedMetric);
			setDebouncedSplitBy(selectedSplitBy);
		}, 300);
		return () => clearTimeout(timer);
	}, [selectedDimension, selectedMetric, selectedSplitBy]);

	const { data: summary } = useAnalyticsQuery(
		orpc.analytics.sessions.summary.queryOptions({ input: { days } }),
	);

	const { data: comparison } = useAnalyticsQuery(
		orpc.analytics.sessions.summaryComparison.queryOptions({
			input: { days },
		}),
	);

	const { data: sessions, isLoading } = useAnalyticsQuery(
		orpc.analytics.sessions.list.queryOptions({
			input: { days, limit: 100, sortBy: "session_date", sortOrder: "desc" },
		}),
	);

	const { userMap } = useUserMap();

	const { data: dimensionData, isLoading: dimensionLoading } =
		useAnalyticsQuery(
			orpc.analytics.sessions.dimensionAnalysis.queryOptions({
				input: {
					days,
					dimension: debouncedDimension,
					metric: debouncedMetric,
					splitBy: debouncedSplitBy || undefined,
					limit: 10,
				},
			}),
		);

	const columns = useMemo<ColumnDef<SessionAnalytics>[]>(
		() => [
			{
				accessorKey: "session_id",
				header: "Session ID",
				cell: ({ row }) => (
					<span className="text-accent font-mono text-xs">
						{row.original.session_id.slice(0, 8)}...
					</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.session_date).getTime(),
				id: "date",
				header: "Date",
				cell: ({ row }) => (
					<div>
						<span className="text-foreground">
							{new Date(row.original.session_date).toLocaleDateString()}
						</span>
						<br />
						<span className="text-xs text-muted">
							{new Date(row.original.session_date).toLocaleTimeString()}
						</span>
					</div>
				),
			},
			{
				accessorFn: (row) => formatUsername(row.user_id, userMap),
				id: "user",
				header: "User",
				cell: ({ row }) => (
					<span className="text-subheading">
						{formatUsername(row.original.user_id, userMap)}
					</span>
				),
			},
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => (
					<div
						className="max-w-xs truncate"
						title={row.original.git_remote || row.original.project_path}
					>
						{row.original.git_remote
							? row.original.git_remote.split("/").pop()
							: row.original.project_path.split("/").pop() ||
								row.original.project_path}
					</div>
				),
			},
			{
				accessorKey: "duration_min",
				header: "Duration",
				cell: ({ row }) => (
					<span className="text-foreground">
						{row.original.duration_min.toFixed(0)} min
					</span>
				),
			},
			{
				accessorKey: "success_score",
				header: () => (
					<span className="flex items-center">
						Success Score
						<InfoTooltip text="Session quality score (0–100): earns points for a git commit (+20), high output ratio (+15), and skills used (+5 each, max 3); loses points for errors (−2 each) and abandoned sessions." />
					</span>
				),
				cell: ({ row }) => {
					const score = row.original.success_score;
					const color =
						score >= 70
							? "text-status-success-icon"
							: score >= 40
								? "text-status-warning-icon"
								: "text-status-error-icon";
					return (
						<>
							<span className={`font-semibold ${color}`}>
								{score.toFixed(0)}
							</span>
							<span className="text-xs text-muted"> / 100</span>
						</>
					);
				},
			},
			{
				accessorFn: (row) => calculateCost(row.input_tokens, row.output_tokens),
				id: "cost",
				header: "Cost",
				cell: ({ row }) => (
					<span className="text-foreground font-mono">
						$
						{calculateCost(
							row.original.input_tokens,
							row.original.output_tokens,
						).toFixed(4)}
					</span>
				),
			},
		],
		[userMap],
	);

	const filteredSessions = useMemo(() => {
		if (!sessions) return [];
		return sessions.filter((session) => {
			const repoMatch =
				selectedRepositories.length === 0 ||
				(session.repository &&
					selectedRepositories.includes(session.repository));
			const userMatch =
				selectedUsers.length === 0 || selectedUsers.includes(session.user_id);
			return repoMatch && userMatch;
		});
	}, [sessions, selectedRepositories, selectedUsers]);

	const repositories = useMemo(() => {
		if (!sessions) return [];
		return Array.from(
			new Set(sessions.map((s) => s.repository).filter(Boolean)),
		).sort() as string[];
	}, [sessions]);

	const userOptions = useMemo(() => {
		return Object.entries(userMap).map(([userId, name]) => ({
			id: userId,
			label: name,
		}));
	}, [userMap]);

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Sessions"
					description="Analyze session interaction timing and patterns"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading session analytics...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Sessions"
				description="Analyze session interaction timing and patterns"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{summary && comparison && (
				<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 mb-8">
					<StatCard
						title="Total Sessions"
						value={summary.total_sessions.toLocaleString()}
						icon={Activity}
						iconColor="text-blue-600"
						trend={{ value: comparison.changes.total_sessions }}
					/>
					<StatCard
						title="Avg Session Duration"
						value={`${summary.avg_session_duration_min.toFixed(1)} min`}
						icon={Clock}
						iconColor="text-purple-600"
						trend={{ value: comparison.changes.avg_session_duration_min }}
					/>
					<StatCard
						title="Avg Response Time"
						value={`${summary.avg_response_time_sec.toFixed(1)}s`}
						icon={Timer}
						iconColor="text-green-600"
						trend={{ value: comparison.changes.avg_response_time_sec }}
					/>
				</div>
			)}

			{/* Dimension Analysis */}
			<AnalyticsCard className="mb-8">
				<h3 className="text-lg font-semibold mb-4">
					Multi-Dimensional Analysis
				</h3>
				<p className="text-sm text-muted mb-6">
					Analyze sessions across different dimensions and metrics.
				</p>

				<div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
					<div>
						<label
							htmlFor="sessions-metric-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Measure (Y-Axis)
						</label>
						<Select
							value={selectedMetric}
							onValueChange={(v) =>
								setSelectedMetric(v as DimensionAnalysisInput["metric"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_count">Session Count</SelectItem>
								<SelectItem value="avg_duration">Avg Duration (min)</SelectItem>
								<SelectItem value="total_duration">
									Total Duration (hours)
								</SelectItem>
								<SelectItem value="avg_tokens">Avg Tokens</SelectItem>
								<SelectItem value="total_tokens">Total Tokens</SelectItem>
								<SelectItem value="avg_success_score">
									Avg Success Score
								</SelectItem>
								<SelectItem value="total_errors">Total Errors</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-dimension-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Group By (X-Axis)
						</label>
						<Select
							value={selectedDimension}
							onValueChange={(v) =>
								setSelectedDimension(v as DimensionAnalysisInput["dimension"])
							}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="project_path">Project</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
								<SelectItem value="has_commit">Has Commit</SelectItem>
							</SelectContent>
						</Select>
					</div>
					<div>
						<label
							htmlFor="sessions-splitby-select"
							className="block text-sm font-medium text-subheading mb-2"
						>
							Split By (Optional)
						</label>
						<Select
							value={selectedSplitBy || "none"}
							onValueChange={(v) => {
								const value = v === "none" ? "" : v;
								setSelectedSplitBy(
									value as DimensionAnalysisInput["dimension"] | "",
								);
								if (!value) setShowPercentage(false);
							}}
						>
							<SelectTrigger className="w-full">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="none">None</SelectItem>
								<SelectItem value="session_archetype">Session Type</SelectItem>
								<SelectItem value="model_used">Model Used</SelectItem>
								<SelectItem value="user_id">User/Developer</SelectItem>
								<SelectItem value="repository">Repository</SelectItem>
							</SelectContent>
						</Select>
					</div>
				</div>

				{selectedSplitBy && (
					<div className="mb-4 flex justify-end items-center gap-3">
						<span className="text-sm text-muted">Scale to 100%</span>
						<Switch
							checked={showPercentage}
							onCheckedChange={setShowPercentage}
						/>
					</div>
				)}

				{dimensionLoading ? (
					<div className="flex items-center justify-center h-64">
						<div className="text-center">
							<Spinner className="mb-2" />
							<p className="text-muted">Loading chart...</p>
						</div>
					</div>
				) : (
					<DimensionAnalysisChart
						data={dimensionData || []}
						dimension={selectedDimension}
						metric={selectedMetric}
						split_by={selectedSplitBy || undefined}
						showPercentage={showPercentage}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Sessions Table */}
			<AnalyticsCard>
				<div className="flex items-center justify-between mb-4">
					<div>
						<h3 className="text-lg font-semibold">
							Recent Sessions ({filteredSessions.length})
						</h3>
					</div>
					<div className="flex gap-3">
						<MultiSelect
							options={repositories}
							selected={selectedRepositories}
							onChange={setSelectedRepositories}
							placeholder="All Repositories"
							className="w-48"
						/>
						<MultiSelect
							options={userOptions.map((u) => u.label)}
							selected={selectedUsers.map((id) => userMap[id] || id)}
							onChange={(selectedNames) => {
								const ids = selectedNames.map((name) => {
									const match = userOptions.find((u) => u.label === name);
									return match ? match.id : name;
								});
								setSelectedUsers(ids);
							}}
							placeholder="All Developers"
							className="w-48"
						/>
					</div>
				</div>

				<DataTable
					columns={columns}
					data={filteredSessions}
					defaultSorting={[{ id: "date", desc: true }]}
					onRowClick={(row) =>
						navigate(`/dashboard/sessions/${row.session_id}`)
					}
				/>
			</AnalyticsCard>
		</div>
	);
}

import { AlertCircle, AlertTriangle, Clock, Users } from "lucide-react";
import { useState } from "react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ErrorTrendChart } from "@/components/charts/ErrorTrendChart";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useUserMap } from "@/hooks/useUserMap";
import { orpc } from "@/lib/orpc";

const severityColors = {
	high: "bg-status-error-bg text-status-error-text border-status-error-border",
	medium:
		"bg-status-warning-bg text-status-warning-text border-status-warning-border",
	low: "bg-status-info-bg text-status-info-text border-status-info-border",
};

const severityIcons = {
	high: "\u{1F534}",
	medium: "\u{1F7E1}",
	low: "\u{1F535}",
};

export function ErrorsPage() {
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const days = calculateDays();

	const [trendMetric, setTrendMetric] = useState<
		"avg_errors_per_interaction" | "avg_errors_per_session" | "total_errors"
	>("total_errors");
	const [trendSplitBy, setTrendSplitBy] = useState<
		"project_path" | "user_id" | "model"
	>("project_path");

	const { data: errors, isLoading } = useAnalyticsQuery(
		orpc.analytics.errors.topRecurring.queryOptions({
			input: { days, minOccurrences: 2, limit: 15 },
		}),
	);

	const { data: trendData, isLoading: trendLoading } = useAnalyticsQuery(
		orpc.analytics.errors.trends.queryOptions({
			input: { startDate, endDate, splitBy: trendSplitBy },
		}),
	);

	const { userMap } = useUserMap();

	const totalErrors = errors?.reduce((sum, e) => sum + e.occurrences, 0) ?? 0;
	const highSeverityCount =
		errors?.filter((e) => e.severity === "high").length ?? 0;
	const affectedUsersTotal =
		errors && errors.length > 0
			? Math.max(...errors.map((e) => e.affected_users))
			: 0;
	const mostCommonError =
		errors && errors.length > 0 ? errors[0].error_pattern : "None";

	if (isLoading) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Error Intelligence"
					description="Track and analyze recurring errors across your team"
					actions={
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading error data...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Error Intelligence"
				description="Track and analyze recurring errors across your team"
				actions={
					<DatePicker
						startDate={startDate}
						endDate={endDate}
						onStartDateChange={setStartDate}
						onEndDateChange={setEndDate}
					/>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Errors"
					value={totalErrors.toLocaleString()}
					subtitle="error occurrences"
					icon={AlertCircle}
					iconColor="text-red-600"
				/>
				<StatCard
					title="High Severity"
					value={highSeverityCount}
					subtitle="critical issues"
					icon={AlertTriangle}
					iconColor="text-orange-600"
				/>
				<StatCard
					title="Most Common"
					value={mostCommonError}
					subtitle="top error type"
					icon={Clock}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Max Affected Users"
					value={affectedUsersTotal}
					subtitle="developers impacted"
					icon={Users}
					iconColor="text-blue-600"
				/>
			</div>

			{/* Error Trends Chart */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-2">
					Error Trends Over Time
				</h2>
				<p className="text-sm text-muted mb-6">
					Track error metrics across different dimensions to identify patterns
					and trends
				</p>
				{trendLoading ? (
					<div className="text-center py-12 text-muted">
						Loading error trends...
					</div>
				) : (
					<ErrorTrendChart
						data={trendData || []}
						metric={trendMetric}
						splitBy={trendSplitBy}
						onMetricChange={setTrendMetric}
						onSplitByChange={setTrendSplitBy}
						userMap={userMap}
					/>
				)}
			</AnalyticsCard>

			{/* Top Recurring Errors */}
			<AnalyticsCard className="mb-8">
				<h2 className="text-xl font-bold text-heading mb-4">
					Top Recurring Errors
				</h2>
				<p className="text-sm text-muted mb-6">
					Most frequently occurring errors that may need attention
				</p>
				{errors && errors.length > 0 ? (
					<div className="space-y-4">
						{errors.map((err, index) => (
							<div
								// biome-ignore lint/suspicious/noArrayIndexKey: static list of errors
								key={index}
								className="border border-border rounded-lg p-4 hover:shadow-md transition-shadow"
							>
								<div className="flex items-start justify-between">
									<div className="flex-1">
										<div className="flex items-center gap-3 mb-2">
											<span className="text-2xl">
												{
													severityIcons[
														err.severity as keyof typeof severityIcons
													]
												}
											</span>
											<h3 className="text-lg font-semibold text-heading">
												{err.error_pattern}
											</h3>
											<span
												className={`px-3 py-1 rounded-full text-xs font-medium border ${
													severityColors[
														err.severity as keyof typeof severityColors
													]
												}`}
											>
												{err.severity.toUpperCase()}
											</span>
										</div>
										<div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-3">
											<div>
												<p className="text-xs text-muted uppercase">
													Occurrences
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.occurrences}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Affected Users
												</p>
												<p className="text-lg font-semibold text-foreground">
													{err.affected_users}
												</p>
											</div>
											<div>
												<p className="text-xs text-muted uppercase">
													Last Seen
												</p>
												<p className="text-sm text-subheading">
													{new Date(err.last_seen).toLocaleDateString()}
												</p>
											</div>
										</div>
									</div>
								</div>
							</div>
						))}
					</div>
				) : (
					<div className="text-center py-12">
						<div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-status-success-bg mb-4">
							<svg
								className="w-8 h-8 text-status-success-icon"
								fill="none"
								stroke="currentColor"
								viewBox="0 0 24 24"
								role="img"
								aria-label="No errors"
							>
								<path
									strokeLinecap="round"
									strokeLinejoin="round"
									strokeWidth={2}
									d="M5 13l4 4L19 7"
								/>
							</svg>
						</div>
						<p className="text-lg font-medium text-foreground mb-1">
							No recurring errors found!
						</p>
						<p className="text-sm text-muted">
							Great job! Your team hasn't encountered any recurring errors in
							the selected time period.
						</p>
					</div>
				)}
			</AnalyticsCard>

			{/* Error Insights */}
			{errors && errors.length > 0 && (
				<div className="grid grid-cols-1 md:grid-cols-2 gap-6">
					<AnalyticsCard className="bg-status-error-bg border-status-error-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-error-bg">
								<AlertTriangle className="h-6 w-6 text-status-error-icon" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Action Recommended
								</h3>
								<p className="text-sm text-subheading mb-3">
									You have {highSeverityCount} high-severity error
									{highSeverityCount !== 1 ? "s" : ""} that may require
									immediate attention.
								</p>
								{highSeverityCount > 0 && (
									<p className="text-xs text-muted">
										Consider scheduling a team discussion to address these
										issues.
									</p>
								)}
							</div>
						</div>
					</AnalyticsCard>

					<AnalyticsCard className="bg-status-info-bg border-status-info-border">
						<div className="flex items-start gap-4">
							<div className="p-3 rounded-lg bg-status-info-bg">
								<Users className="h-6 w-6 text-accent" />
							</div>
							<div className="flex-1">
								<h3 className="text-lg font-semibold text-heading mb-2">
									Knowledge Sharing
								</h3>
								<p className="text-sm text-subheading mb-3">
									{errors.filter((e) => e.affected_users > 1).length} error type
									{errors.filter((e) => e.affected_users > 1).length !== 1
										? "s"
										: ""}{" "}
									affecting multiple developers.
								</p>
								<p className="text-xs text-muted">
									Share solutions in team channels to help everyone learn.
								</p>
							</div>
						</div>
					</AnalyticsCard>
				</div>
			)}
		</div>
	);
}

