							/>
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend
								layout="vertical"
								align="right"
								verticalAlign="top"
								width={140}
								content={({ payload }) => <ChartLegend payload={payload} />}
							/>
							<Bar
								yAxisId="left"
								dataKey="sessions"
								fill="#3b82f6"
								name="Sessions"
							/>
							<Bar
								yAxisId="right"
								dataKey="hours"
								fill="#10b981"
								name="Hours"
							/>
						</BarChart>
					</ResponsiveContainer>
					{contributors && (
						<div className="mt-6">
							<DataTable
								columns={contributorColumns}
								data={contributors}
								defaultSorting={[{ id: "sessions", desc: true }]}
								defaultPageSize={50}
							/>
						</div>
					)}
				</AnalyticsCard>
			)}

			{errors && errors.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Errors Encountered
					</h2>
					<DataTable
						columns={projectErrorColumns}
						data={errors}
						defaultSorting={[{ id: "occurrences", desc: true }]}
						defaultPageSize={50}
					/>
				</AnalyticsCard>
			)}
		</div>
	);
}

