import type { DeveloperError, DeveloperSession } from "@rudel/api-routes";
import type { ColumnDef } from "@tanstack/react-table";
import { Activity, ArrowLeft, Calendar, Clock, Code, Zap } from "lucide-react";
import { useMemo, useState } from "react";
import { Link, useNavigate, useParams } from "react-router-dom";
import {
	Bar,
	BarChart,
	CartesianGrid,
	Legend,
	Line,
	LineChart,
	ResponsiveContainer,
	Tooltip,
	XAxis,
	YAxis,
} from "recharts";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { ChartCard } from "@/components/analytics/ChartCard";
import { DatePicker } from "@/components/analytics/DatePicker";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { Button } from "@/components/ui/button";
import { DataTable } from "@/components/ui/data-table";
import {
	Select,
	SelectContent,
	SelectItem,
	SelectTrigger,
	SelectValue,
} from "@/components/ui/select";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { useChartTheme } from "@/hooks/useChartTheme";
import { useUserMap } from "@/hooks/useUserMap";
import {
	calculateRollingAverage,
	calculateWeekOverWeek,
	formatWoWChange,
	getTrendColor,
	getTrendDirection,
	getTrendIcon,
} from "@/lib/analytics";
import { formatUsername } from "@/lib/format";
import { orpc } from "@/lib/orpc";

function resolveProjectName(row: {
	git_remote?: string;
	package_name?: string;
	project_path: string;
}): { name: string; tooltip?: string } {
	if (row.git_remote) {
		return {
			name: row.git_remote.split("/").pop() || row.git_remote,
			tooltip: row.git_remote,
		};
	}
	if (row.package_name) {
		return { name: row.package_name };
	}
	return { name: row.project_path.split("/").pop() || row.project_path };
}

export function DeveloperDetailPage() {
	const { userId } = useParams<{ userId: string }>();
	const navigate = useNavigate();
	const { startDate, endDate, setStartDate, setEndDate, calculateDays } =
		useDateRange();
	const chartTheme = useChartTheme();
	const days = calculateDays();

	const [projectFilter, setProjectFilter] = useState<string>("");
	const [outcomeFilter, setOutcomeFilter] = useState<"all" | "success">("all");

	const { data: details, isLoading: detailsLoading } = useAnalyticsQuery(
		orpc.analytics.developers.details.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: sessions } = useAnalyticsQuery(
		orpc.analytics.developers.sessions.queryOptions({
			input: {
				userId: userId as string,
				days,
				limit: 100,
				projectPath: projectFilter || undefined,
				outcome: outcomeFilter,
				sortBy: "date" as const,
				sortOrder: "desc" as const,
			},
		}),
	);

	const { data: projects } = useAnalyticsQuery(
		orpc.analytics.developers.projects.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: timeline } = useAnalyticsQuery(
		orpc.analytics.developers.timeline.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: features } = useAnalyticsQuery(
		orpc.analytics.developers.features.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { data: errors } = useAnalyticsQuery(
		orpc.analytics.developers.errors.queryOptions({
			input: { userId: userId as string, days },
		}),
	);

	const { userMap } = useUserMap();

	const username = formatUsername(userId || "", userMap);

	const chartData = useMemo(() => {
		if (!timeline) return [];
		const sessionValues = timeline.map((d) => d.sessions);
		const rollingAvg7 = calculateRollingAverage(sessionValues, 7);
		const rollingAvg30 = calculateRollingAverage(sessionValues, 30);

		return timeline.map((day, index) => ({
			date: new Date(day.date).toLocaleDateString("en-US", {
				month: "short",
				day: "numeric",
			}),
			sessions: day.sessions,
			hours: parseFloat((day.total_duration_min / 60).toFixed(1)),
			avg7Sessions: rollingAvg7[index],
			avg30Sessions: rollingAvg30[index],
		}));
	}, [timeline]);

	const { wowChange, trendIcon } = useMemo(() => {
		if (!timeline || timeline.length < 14) {
			return {
				wowChange: 0,
				trendColorClass: "text-gray-500",
				trendIcon: "\u2192",
			};
		}
		const sessionValues = timeline.map((d) => d.sessions);
		const currentWeek = sessionValues.slice(-7);
		const previousWeek = sessionValues.slice(-14, -7);
		const wow = calculateWeekOverWeek(currentWeek, previousWeek);
		const direction = getTrendDirection(sessionValues);
		return {
			wowChange: wow,
			trendColorClass: getTrendColor(direction),
			trendIcon: getTrendIcon(direction),
		};
	}, [timeline]);

	const projectChartData = useMemo(() => {
		if (!projects) return [];
		return projects.slice(0, 10).map((p) => ({
			name: resolveProjectName(p).name,
			sessions: p.sessions,
			hours: parseFloat((p.total_duration_min / 60).toFixed(1)),
		}));
	}, [projects]);

	const uniqueProjects = useMemo(() => {
		if (!sessions) return [];
		const seen = new Map<string, { path: string; name: string }>();
		for (const s of sessions) {
			if (!seen.has(s.project_path)) {
				seen.set(s.project_path, {
					path: s.project_path,
					name: resolveProjectName(s).name,
				});
			}
		}
		return Array.from(seen.values());
	}, [sessions]);

	const errorColumns = useMemo<ColumnDef<DeveloperError>[]>(
		() => [
			{
				accessorKey: "error_pattern",
				header: "Error Type",
				cell: ({ row }) => (
					<span className="font-medium text-foreground">
						{row.original.error_pattern}
					</span>
				),
			},
			{
				accessorKey: "occurrences",
				header: "Occurrences",
				cell: ({ row }) => (
					<span className="text-muted">{row.original.occurrences}</span>
				),
			},
			{
				accessorFn: (row) => new Date(row.last_seen).getTime(),
				id: "last_seen",
				header: "Last Seen",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.last_seen).toLocaleDateString()}
					</span>
				),
			},
		],
		[],
	);

	const sessionColumns = useMemo<ColumnDef<DeveloperSession>[]>(
		() => [
			{
				accessorFn: (row) => new Date(row.session_date).getTime(),
				id: "date",
				header: "Date",
				cell: ({ row }) => (
					<span className="text-muted">
						{new Date(row.original.session_date).toLocaleString()}
					</span>
				),
			},
			{
				accessorKey: "project_path",
				header: "Project",
				cell: ({ row }) => {
					const { name, tooltip } = resolveProjectName(row.original);
					return (
						<span className="font-medium text-foreground" title={tooltip}>
							{name}
						</span>
					);
				},
			},
			{
				accessorKey: "duration_min",
				header: "Duration",
				cell: ({ row }) => (
					<span className="text-muted">
						{row.original.duration_min.toFixed(0)}m
					</span>
				),
			},
			{
				accessorKey: "total_tokens",
				header: "Tokens",
				cell: ({ row }) => (
					<span className="text-muted">
						{(row.original.total_tokens / 1000).toFixed(0)}K
					</span>
				),
			},
			{
				id: "features",
				header: "Features",
				enableSorting: false,
				cell: ({ row }) => (
					<div className="flex gap-1">
						{row.original.has_subagents && (
							<span className="px-2 py-1 text-xs bg-blue-100 text-blue-800 rounded">
								SA
							</span>
						)}
						{row.original.has_skills && (
							<span className="px-2 py-1 text-xs bg-purple-100 text-purple-800 rounded">
								SK
							</span>
						)}
						{row.original.has_slash_commands && (
							<span className="px-2 py-1 text-xs bg-green-100 text-green-800 rounded">
								SC
							</span>
						)}
					</div>
				),
			},
			{
				id: "status",
				header: "Status",
				enableSorting: false,
				cell: ({ row }) => {
					if (row.original.likely_success) {
						return (
							<span className="px-2 py-1 text-xs bg-status-success-bg text-status-success-text rounded-full">
								Success
							</span>
						);
					}
					if (row.original.has_errors) {
						return (
							<span className="px-2 py-1 text-xs bg-status-error-bg text-status-error-text rounded-full">
								Error
							</span>
						);
					}
					return (
						<span className="px-2 py-1 text-xs bg-surface text-subheading rounded-full">
							Unknown
						</span>
					);
				},
			},
		],
		[],
	);

	if (detailsLoading || !details) {
		return (
			<div className="px-8 py-6">
				<PageHeader
					title="Developer Details"
					description="Loading developer information..."
					actions={
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/developers">
								<ArrowLeft className="h-4 w-4" />
								Back to Developers
							</Link>
						</Button>
					}
				/>
				<AnalyticsCard>
					<p className="text-center text-muted">Loading...</p>
				</AnalyticsCard>
			</div>
		);
	}

	return (
		<div className="px-8 py-6">
			<PageHeader
				title={username}
				description="Detailed developer activity and metrics"
				actions={
					<div className="flex items-center gap-3">
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
						<Button variant="outline" size="sm" asChild>
							<Link to="/dashboard/developers">
								<ArrowLeft className="h-4 w-4" />
								Back
							</Link>
						</Button>
					</div>
				}
			/>

			{/* Summary Stats */}
			<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
				<StatCard
					title="Total Sessions"
					value={details.total_sessions}
					icon={Activity}
					iconColor="text-blue-600"
				/>
				<StatCard
					title="Active Days"
					value={details.active_days}
					icon={Calendar}
					iconColor="text-green-600"
				/>
				<StatCard
					title="Total Tokens"
					value={`${(details.total_tokens / 1000000).toFixed(1)}M`}
					icon={Code}
					iconColor="text-purple-600"
				/>
				<StatCard
					title="Avg Session"
					value={`${details.avg_session_duration_min.toFixed(0)}m`}
					icon={Clock}
					iconColor="text-orange-600"
				/>
			</div>

			{/* Activity Timeline */}
			{chartData.length > 0 && (
				<ChartCard title={`Daily Activity ${trendIcon}`} className="mb-8">
					{timeline && timeline.length >= 14 && (
						<div className="flex justify-end mb-4">
							<div className="bg-surface px-4 py-2 rounded-lg">
								<p className="text-xs text-muted">Week-over-Week</p>
								<p
									className={`text-lg font-bold ${wowChange >= 0 ? "text-status-success-icon" : "text-status-error-icon"}`}
								>
									{formatWoWChange(wowChange)}
								</p>
							</div>
						</div>
					)}
					<ResponsiveContainer width="100%" height={300}>
						<LineChart data={chartData}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke={chartTheme.gridStroke}
							/>
							<XAxis dataKey="date" stroke={chartTheme.axisStroke} />
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend />
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="sessions"
								stroke="#3b82f6"
								strokeWidth={2}
								name="Sessions"
							/>
							<Line
								yAxisId="right"
								type="monotone"
								dataKey="hours"
								stroke="#10b981"
								strokeWidth={2}
								name="Hours"
							/>
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="avg7Sessions"
								stroke="#93c5fd"
								strokeWidth={2}
								strokeDasharray="5 5"
								name="7-Day Avg"
								dot={false}
							/>
							<Line
								yAxisId="left"
								type="monotone"
								dataKey="avg30Sessions"
								stroke="#fb923c"
								strokeWidth={2}
								strokeDasharray="5 5"
								name="30-Day Avg"
								dot={false}
							/>
						</LineChart>
					</ResponsiveContainer>
				</ChartCard>
			)}

			{/* Feature Adoption */}
			{features && (
				<div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Subagents</p>
								<p className="text-2xl font-bold text-heading">
									{features.subagents_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-blue-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Skills</p>
								<p className="text-2xl font-bold text-heading">
									{features.skills_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-purple-600" />
						</div>
					</AnalyticsCard>
					<AnalyticsCard>
						<div className="flex items-center justify-between">
							<div>
								<p className="text-sm text-muted">Slash Commands</p>
								<p className="text-2xl font-bold text-heading">
									{features.slash_commands_adoption_rate.toFixed(0)}%
								</p>
							</div>
							<Zap className="h-8 w-8 text-green-600" />
						</div>
					</AnalyticsCard>
				</div>
			)}

			{/* Projects */}
			{projectChartData.length > 0 && (
				<ChartCard title="Projects Worked On" className="mb-8">
					<ResponsiveContainer width="100%" height={350}>
						<BarChart data={projectChartData}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke={chartTheme.gridStroke}
							/>
							<XAxis
								dataKey="name"
								interval={0}
								stroke={chartTheme.axisStroke}
								tick={{ fontSize: 12 }}
								tickFormatter={(v) =>
									v.length > 12 ? `${v.slice(0, 12)}...` : v
								}
							/>
							<YAxis yAxisId="left" stroke={chartTheme.axisStroke} />
							<YAxis
								yAxisId="right"
								orientation="right"
								stroke={chartTheme.axisStroke}
							/>
							<Tooltip
								contentStyle={{
									backgroundColor: chartTheme.tooltipBg,
									borderColor: chartTheme.tooltipBorder,
								}}
							/>
							<Legend />
							<Bar
								yAxisId="left"
								dataKey="sessions"
								fill="#3b82f6"
								name="Sessions"
							/>
							<Bar
								yAxisId="right"
								dataKey="hours"
								fill="#10b981"
								name="Hours"
							/>
						</BarChart>
					</ResponsiveContainer>
				</ChartCard>
			)}

			{/* Errors */}
			{errors && errors.length > 0 && (
				<AnalyticsCard className="mb-8">
					<h2 className="text-xl font-bold text-heading mb-4">
						Errors Encountered
					</h2>
					<DataTable
						columns={errorColumns}
						data={errors}
						defaultSorting={[{ id: "occurrences", desc: true }]}
						defaultPageSize={50}
					/>
				</AnalyticsCard>
			)}

			{/* Session History */}
			<AnalyticsCard>
				<div className="flex justify-between items-center mb-4">
					<h2 className="text-xl font-bold text-heading">Session History</h2>
					<div className="flex gap-3">
						<Select
							value={projectFilter || "all"}
							onValueChange={(v) => setProjectFilter(v === "all" ? "" : v)}
						>
							<SelectTrigger className="w-auto">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="all">All Projects</SelectItem>
								{uniqueProjects.map((p) => (
									<SelectItem key={p.path} value={p.path}>
										{p.name}
									</SelectItem>
								))}
							</SelectContent>
						</Select>
						<Select
							value={outcomeFilter}
							onValueChange={(v) => setOutcomeFilter(v as "all" | "success")}
						>
							<SelectTrigger className="w-auto">
								<SelectValue />
							</SelectTrigger>
							<SelectContent>
								<SelectItem value="all">All Outcomes</SelectItem>
								<SelectItem value="success">Likely Success</SelectItem>
							</SelectContent>
						</Select>
					</div>
				</div>

				<DataTable
					columns={sessionColumns}
					data={sessions ?? []}
					defaultSorting={[{ id: "date", desc: true }]}
					onRowClick={(row) =>
						navigate(`/dashboard/sessions/${row.session_id}`)
					}
				/>
			</AnalyticsCard>
		</div>
	);
}

import {
	Activity,
	Bot,
	FolderKanban,
	Sparkles,
	Terminal,
	Users,
} from "lucide-react";
import { AnalyticsCard } from "@/components/analytics/AnalyticsCard";
import { ChartCard } from "@/components/analytics/ChartCard";
import { CliSetupHint } from "@/components/analytics/CliSetupHint";
import { DatePicker } from "@/components/analytics/DatePicker";
import { InsightCard } from "@/components/analytics/InsightCard";
import { NoSessionsInRange } from "@/components/analytics/NoSessionsInRange";
import { PageHeader } from "@/components/analytics/PageHeader";
import { StatCard } from "@/components/analytics/StatCard";
import { ModelTokensChart } from "@/components/charts/ModelTokensChart";
import { UsageTrendChart } from "@/components/charts/UsageTrendChart";
import { Spinner } from "@/components/ui/spinner";
import { useDateRange } from "@/contexts/DateRangeContext";
import { useAnalyticsQuery } from "@/hooks/useAnalyticsQuery";
import { orpc } from "@/lib/orpc";

export function OverviewPage() {
	const { startDate, endDate, setStartDate, setEndDate } = useDateRange();

	const {
		data: kpis,
		isPending: kpisLoading,
		isError: kpisError,
	} = useAnalyticsQuery(
		orpc.analytics.overview.kpis.queryOptions({
			input: { startDate, endDate },
		}),
	);

	const { data: usageTrendData } = useAnalyticsQuery(
		orpc.analytics.overview.usageTrend.queryOptions({
			input: { startDate, endDate },
		}),
	);

	const { data: modelTokensData } = useAnalyticsQuery(
		orpc.analytics.overview.modelTokensTrend.queryOptions({
			input: { startDate, endDate },
		}),
	);

	const { data: insights } = useAnalyticsQuery(
		orpc.analytics.overview.insights.queryOptions({
			input: { startDate, endDate },
		}),
	);

	const hasData = !kpisLoading && kpis && kpis.distinct_sessions > 0;
	const hasAnySessions = kpis && kpis.total_sessions > 0;
	const showDatePicker = hasData || (!kpisLoading && hasAnySessions);

	return (
		<div className="px-8 py-6">
			<PageHeader
				title="Dashboard Overview"
				description="Track your team's Claude Code usage and metrics"
				actions={
					showDatePicker ? (
						<DatePicker
							startDate={startDate}
							endDate={endDate}
							onStartDateChange={setStartDate}
							onEndDateChange={setEndDate}
						/>
					) : undefined
				}
			/>

			{kpisLoading && (
				<div className="flex items-center justify-center py-12">
					<div className="text-center">
						<Spinner size="lg" className="mb-4" />
						<p className="text-muted">Loading dashboard data...</p>
					</div>
				</div>
			)}

			{!kpisLoading && !hasData && hasAnySessions && <NoSessionsInRange />}

			{!kpisLoading && (kpisError || (kpis && kpis.total_sessions === 0)) && (
				<CliSetupHint />
			)}

			{hasData && (
				<>
					<div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-4 mb-8">
						<StatCard
							title="Distinct Users"
							value={kpis.distinct_users.toLocaleString()}
							icon={Users}
							iconColor="text-green-600"
							href="/dashboard/developers"
							linkLabel="Go to users"
						/>
						<StatCard
							title="Distinct Sessions"
							value={kpis.distinct_sessions.toLocaleString()}
							icon={Activity}
							iconColor="text-blue-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Distinct Projects"
							value={kpis.distinct_projects.toLocaleString()}
							icon={FolderKanban}
							iconColor="text-purple-600"
							href="/dashboard/projects"
							linkLabel="Go to projects"
						/>
						<StatCard
							title="Distinct Subagents"
							value={kpis.distinct_subagents.toLocaleString()}
							icon={Bot}
							iconColor="text-orange-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Slash Commands"
							value={kpis.distinct_slash_commands.toLocaleString()}
							icon={Terminal}
							iconColor="text-cyan-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
						<StatCard
							title="Distinct Skills"
							value={kpis.distinct_skills.toLocaleString()}
							icon={Sparkles}
							iconColor="text-pink-600"
							href="/dashboard/sessions"
							linkLabel="Go to sessions"
						/>
					</div>

					{insights && insights.length > 0 && (
						<div className="mb-8">
							<h2 className="text-xl font-bold text-heading mb-4">
								Quick Insights
							</h2>
							<div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
								{insights.map((insight, index) => (
									<InsightCard
										// biome-ignore lint/suspicious/noArrayIndexKey: static insights list
										key={index}
										insight={{
											type: insight.type as
												| "trend"
												| "performer"
												| "alert"
												| "info",
											severity: insight.severity,
											message: insight.message,
											link: insight.link || "/dashboard",
										}}
									/>
								))}
							</div>
						</div>
					)}

					{usageTrendData && usageTrendData.length > 0 && (
						<ChartCard
							title="Usage Trends"
							description="Track key metrics over time - switch between metric pairs to see different views"
							className="mb-8"
						>
							<UsageTrendChart
								data={usageTrendData}
								showRollingAverage={false}
							/>
						</ChartCard>
					)}

					{modelTokensData && modelTokensData.length > 0 && (
						<ChartCard
							title="Tokens by Model"
							description="Token consumption broken down by model type over time"
							className="mb-8"
						>
							<ModelTokensChart data={modelTokensData} />
						</ChartCard>
					)}
				</>
			)}
		</div>
	);
}

